---@class StructEquip
local StructEquip = LxClass("StructEquip", nil)
function StructEquip:StructEquip()
    self._refId = 0
    self._num = 0
    self._type = LItemTypeConst.TYPE_EQUIP
    self._score = 0
    self._id = 0  --  装备唯一id
    self._level = 0   -- 强化等级
    self._grade = 0   --魂镜等级
end

function StructEquip:CreateByPb(pb)
    self._refId = pb.refId
    self._num = pb.num or 0
    self._id = pb.id or 0
    self._level = pb.level or 0
    self._grade = pb.grade or 0
    self._exp = pb.exp or 0
    self._gradeExp = pb.gradeExp or 0
    self._refineRefId = pb.refineRefId or 0

    local starScore = gModelEquip:GetEquipRefByRefId(self._refId).score  --星星的战力
    local lvScore, gradeScore, refineScore = gModelEquip:GetStrengthAndRefineScore(self._refId,self._id,self._level,self._grade,self._refineRefId)
    self._score = starScore + lvScore + gradeScore+refineScore
    
    self._ref = gModelEquip:GetEquipRefByRefId(self._refId)
end

function StructEquip:GetRefId()
    return self._refId
end

function StructEquip:GetId()
    return self._id
end

function StructEquip:GetNum()
    return self._num
end

function StructEquip:IsHasEquip()
    return self._num > 0
end

function StructEquip:GetScore()
    return self._score
end

function StructEquip:ChangeNum(num)
    self._num = num
end

function StructEquip:GetType()
    return self._type
end

function StructEquip:GetGrade()
    return tonumber(self._grade)
end

function StructEquip:GetLevel()
    return tonumber(self._level)
end

function StructEquip:GetExp()
    return tonumber(self._exp)
end

function StructEquip:GetGradeExp()
    return tonumber(self._gradeExp)
end

function StructEquip:GetRefineRefId()
    return tonumber(self._refineRefId)
end

function StructEquip:GetServerData()
    local serverData = {
        id = self._id,
        refId = self._refId,
        num = self._num,
        score = self._score,
        itype = self._type,
        level = self._level,
        grade = self._grade,
        exp = self._exp,
        gradeExp = self._gradeExp
    }
    return serverData
end

function StructEquip:GetOrder()
    local sort= 100000000
    
    --order部分 用来扣减
    local order = self._ref.order
    sort= sort -(order * 10000000)
    
    --星星
    local starSort = self._ref.star * 1000000
    sort =sort + starSort

    --加上强化的评分
    local strengthSort  = self._grade * 10000
    sort =sort + strengthSort
    
    --加上refId
    sort = sort+self._refId
    
    return sort 
end

return StructEquip